func emPropForRune(r rune) emProp {
	if r < 256 {
		return emAsciiLookupTbl[r]
	}

	i, j := 0, len(emRanges)
	for i < j {
		mid := i + (j-i)/2
		rng := emRanges[mid]
		if rng.Start <= r && r <= rng.End {
			return rng.Prop
		} else if r < rng.Start {
			j = mid
		} else {
			i = mid + 1
		}
	}
	return emPropNone
}
